window.CA = {"date": "Saturday, 27 June 2026", "updated": "2026-06-27 13:58", "updated_label": "27 Jun 2026, 13:58 IST", "items": [{"title": "PM Modi Visits Seychelles for Golden Jubilee of National Day; to Meet Jonathan, World's Oldest Living Land Animal", "category": "ir", "category_name": "International Relations", "summary": "Prime Minister Narendra Modi departed for Seychelles on June 27, 2026, to attend the golden jubilee celebrations of the island nation's National Day. This is a significant bilateral visit aimed at strengthening India-Seychelles ties in the Indian Ocean Region. Modi is also scheduled to meet Jonathan, the Aldabra giant tortoise widely recognised as the world's oldest living land animal, aged over 190 years.", "exam_angle": "India's 'Neighbourhood First' and 'SAGAR' (Security and Growth for All in the Region) doctrine extends to Indian Ocean island states; Seychelles is a key maritime partner for India in the Western Indian Ocean.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Visit purpose: Golden Jubilee of Seychelles National Day", "Jonathan the tortoise: Aldabra giant tortoise, world's oldest living land animal (190+ years)", "India's policy framework: SAGAR doctrine for Indian Ocean engagement", "Seychelles: Located in Western Indian Ocean; strategic maritime partner of India"], "source": "India Today / The Hindu", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "US Secretary of State Rubio Signals Trump Visit to India 'Early 2027'; India-US Trade Deal in Final Stages", "category": "ir", "category_name": "International Relations", "summary": "US Secretary of State Marco Rubio stated on June 27, 2026, that India-US ties are 'going fantastic' and confirmed that a bilateral trade deal is in its final stages, with only a 'handful of issues' remaining. US Ambassador to India Sergio Gor echoed this, indicating Trump may visit India in early 2027. The announcement reflects the strengthening of the India-US strategic and economic partnership.", "exam_angle": "India-US bilateral trade negotiations are a key GS Paper 2 (IR) and GS Paper 3 (Economy) topic, connecting to issues of tariffs, market access, and strategic partnership under the India-US Comprehensive Global and Strategic Partnership.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Statement by: US Secretary of State Marco Rubio and US Ambassador Sergio Gor", "Trade deal status: Final stages, 'handful of issues left'", "Trump visit: Expected early 2027", "Framework: India-US Comprehensive Global and Strategic Partnership"], "source": "Moneycontrol / NDTV / The Indian Express", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "US Conducts Military Strikes on Iran; Iran Retaliates — Strait of Hormuz and Gulf Security at Risk", "category": "ir", "category_name": "International Relations", "summary": "The United States military conducted strikes on Iran following President Trump's warning about a 'foolish violation' related to a Hormuz-area ship attack. Iran's Islamic Revolutionary Guard Corps (IRGC) subsequently claimed to have targeted US sites in retaliation. Iran also reasserted control over the Strait of Hormuz, warned Gulf states against backing the US, and disrupted tanker traffic near Oman, threatening a fragile ceasefire.", "exam_angle": "The Strait of Hormuz is a critical global oil chokepoint through which approximately 20% of global oil trade passes; escalation here directly impacts India's energy security and crude oil imports, relevant for GS Paper 2 (IR) and GS Paper 3 (Economy/Energy).", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Strait of Hormuz: ~20% of global oil trade passes through it", "IRGC (Islamic Revolutionary Guard Corps): Iran's elite military force involved in the retaliation", "India's exposure: India imports significant crude oil from Gulf region", "UAE cities Dubai and Abu Dhabi issued missile attack alerts"], "source": "Times of India / Al Jazeera / Moneycontrol", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Supreme Court: Homebuyers Can Claim Delay Compensation Even After Taking Possession", "category": "polity", "category_name": "Polity & Governance", "summary": "The Supreme Court of India ruled on June 27, 2026, that homebuyers are entitled to seek relief and claim compensation for delays in possession even after they have accepted possession of a property. The court also held that the mere existence of an arbitration clause does not oust the jurisdiction of consumer forums. This ruling significantly strengthens the rights of homebuyers under consumer protection law.", "exam_angle": "This ruling is relevant to the Consumer Protection Act, RERA (Real Estate Regulation and Development Act, 2016), and the scope of consumer forums vs. arbitration — a recurring theme in GS Paper 2 (Polity/Governance) and Prelims.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Ruling: Homebuyers can claim delay compensation even post-possession", "Arbitration clause does NOT oust consumer forum jurisdiction", "Relevant Acts: Consumer Protection Act; RERA 2016", "Body: Supreme Court of India"], "source": "Times of India / NDTV", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "India-New Zealand Free Trade Agreement: A Modern Trade Partnership", "category": "economy", "category_name": "Economy & Banking", "summary": "Reports indicate India and New Zealand are working towards a modern Free Trade Agreement (FTA), covering goods, services, and investment. The FTA is described as a 'modern trade partnership' with potential benefits for Indian IT services, pharmaceuticals, and agricultural products. New Zealand is a significant source of dairy imports and educational services for India.", "exam_angle": "India's FTA negotiations are a key GS Paper 3 (Economy) and GS Paper 2 (IR) topic — issues of non-tariff barriers, dairy sector sensitivities, and the strategic dimension of trade deals in the Indo-Pacific are important.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["FTA covers: Goods, services, and investment", "Sensitive sector for India: Dairy (New Zealand is a major dairy exporter)", "India's export interest: IT services, pharmaceuticals", "Context: India has FTAs with UAE, Australia (ECTA) in recent years"], "source": "The Hindu", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "ITC Flags Twin Risks for Indian Economy: West Asia Conflict and Weak Monsoon", "category": "economy", "category_name": "Economy & Banking", "summary": "ITC Limited, in its latest assessment, flagged two major downside risks to India's economic growth — the escalating West Asia conflict (particularly around the Strait of Hormuz) and a potentially weak monsoon season. The West Asia conflict threatens to spike crude oil prices and disrupt supply chains, while a weak monsoon could hurt agricultural output and rural demand, impacting GDP growth.", "exam_angle": "This connects GS Paper 3 themes of inflation, energy security, agricultural dependence on monsoon, and external sector vulnerabilities — all standard UPSC Mains topics.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Risk 1: West Asia conflict → crude oil price spike, supply chain disruption", "Risk 2: Weak monsoon → lower agricultural output, reduced rural demand", "Source of assessment: ITC Limited", "India imports ~85% of its crude oil requirement"], "source": "Telegraph India", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Anthropic's Mythos 5 AI Model Receives US Government Approval for Limited Rollout; India Assured of Stable Access", "category": "scitech", "category_name": "Science & Technology", "summary": "US AI company Anthropic received approval from the Trump administration for a limited rollout of its advanced 'Mythos 5' AI model to trusted partners, after it had been temporarily blocked over national security concerns. The US assured India of stable access to the AI technology following the temporary suspension. OpenAI similarly briefed the US government before releasing a powerful new AI model, and also limited access to 'trusted partners' at the government's request.", "exam_angle": "AI governance, national security implications of frontier AI models, and the US-India technology partnership (iCET framework) are key topics for GS Paper 3 (Sci-Tech) and GS Paper 2 (IR).", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Model: Anthropic's 'Mythos 5' AI — blocked then partially cleared by US government", "Reason for block: National security concerns", "US-India: US assured India of stable AI technology access", "iCET (Initiative on Critical and Emerging Technologies): Framework governing US-India tech cooperation"], "source": "The New Indian Express / Business Standard / Hindustan Times", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Nasscom: 25% of Indian Tech Services Firms Have Moved AI Experiments to Production Level", "category": "scitech", "category_name": "Science & Technology", "summary": "Industry body Nasscom reported that 25% of Indian technology services companies have successfully transitioned their Artificial Intelligence experiments from pilot/proof-of-concept stage to full production-level deployment. This marks a significant milestone in India's AI adoption in the technology services sector, which is the country's largest export earner.", "exam_angle": "India's IT sector AI adoption rate is relevant for GS Paper 3 (Economy/Sci-Tech), connecting to the National AI Strategy, IndiaAI Mission, and India's competitive positioning in global tech services.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Source: Nasscom (National Association of Software and Service Companies)", "Statistic: 25% of Indian tech firms have moved AI to production level", "Sector: IT/Technology services — India's largest export sector (~$250 bn+ industry)", "Relevant policy: IndiaAI Mission (launched 2024, ₹10,372 crore)"], "source": "The Hindu", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "India Tops Global Research Paper Retraction List: 6 Universities in Top 10", "category": "reports", "category_name": "Reports & Indices", "summary": "A global analysis revealed that India tops the list of countries with the most research paper retractions, with six Indian universities featuring in the top 10 globally. This raises serious concerns about research integrity, academic fraud, and the quality of scientific output from Indian institutions. The findings have implications for India's ambitions to become a global research and innovation hub.", "exam_angle": "Research integrity and quality of Indian higher education/research output are relevant for GS Paper 2 (Education/Governance) and connect to NEP 2020 goals of improving research quality and the ANRF (Anusandhan National Research Foundation).", "gs_paper": "GS Paper 2 (Governance)", "key_facts": ["India: Tops global research paper retraction list", "6 Indian universities in global top 10 for retractions", "Concern: Research fraud, plagiarism, and academic integrity", "Relevant body: ANRF (Anusandhan National Research Foundation) — set up under NEP 2020 to boost research"], "source": "India Today", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Qatar Repatriates Bodies of All 12 Indians Killed in Ras Laffan Gas Facility Fire", "category": "ir", "category_name": "International Relations", "summary": "Qatar completed the repatriation of all 12 bodies of Indian nationals killed in an industrial accident at the Ras Laffan gas facility. Eight of the remaining bodies were repatriated on June 27, 2026, completing the process. Ras Laffan is Qatar's major industrial city and the hub of its liquefied natural gas (LNG) production, where many Indian workers are employed.", "exam_angle": "Indian diaspora welfare, consular services, and India's bilateral ties with Qatar (a major LNG supplier and host of a large Indian worker community) are relevant for GS Paper 2 (IR) and GS Paper 3 (Economy/Energy).", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Incident: Industrial accident at Ras Laffan gas facility, Qatar", "Casualties: 12 Indian nationals killed", "Ras Laffan: Qatar's major LNG production hub", "India-Qatar: ~800,000 Indian diaspora in Qatar; Qatar is a key LNG supplier to India"], "source": "The New Indian Express / India Today", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Venezuela Earthquake Death Toll Rises to 920; 50,000 Still Missing After Four Days", "category": "places", "category_name": "Places in News", "summary": "Four days after a series of deadly earthquakes struck Venezuela, the official death toll has risen to at least 920, with approximately 50,000 people still reported missing. Rescue operations continue amid difficult conditions. The earthquake is one of the deadliest natural disasters in Latin America in recent years.", "exam_angle": "Major international disasters are relevant for GS Paper 1 (Geography — earthquake-prone zones, tectonic plates) and GS Paper 2 (IR — humanitarian response, UN disaster management frameworks like Sendai Framework).", "gs_paper": "GS Paper 1 (Geography)", "key_facts": ["Country affected: Venezuela", "Death toll: At least 920 (as of June 27, 2026)", "Missing persons: ~50,000", "Venezuela lies in a seismically active zone in northern South America near the Caribbean Plate"], "source": "NDTV / The Hindu / BBC", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Mirwaiz Umar Farooq Calls for Direct India-Pakistan Dialogue", "category": "polity", "category_name": "Polity & Governance", "summary": "Mirwaiz Umar Farooq, the Hurriyat Conference chairman and chief religious leader of Kashmir, publicly called for direct talks between India and Pakistan on June 27, 2026. The call comes in the context of ongoing tensions between the two countries and the broader issue of Jammu & Kashmir's political status. Mirwaiz has historically been a significant figure in Kashmiri political discourse.", "exam_angle": "The J&K political situation, India-Pakistan relations, and the role of separatist/moderate voices in Kashmir are important for GS Paper 2 (Polity/IR), particularly questions on internal security and bilateral relations.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Person: Mirwaiz Umar Farooq — Chairman, Hurriyat Conference; Chief Cleric of Kashmir", "Demand: Direct India-Pakistan dialogue", "Context: Post-Article 370 abrogation (August 5, 2019), J&K remains a Union Territory", "Hurriyat Conference: An amalgam of separatist groups in J&K"], "source": "NDTV", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "NEP 2020 and India's Education Crisis: Frontline Analysis", "category": "schemes", "category_name": "Govt Schemes & Policies", "summary": "Frontline Magazine published an analysis of the implementation of the National Education Policy (NEP) 2020 and the challenges facing India's education system, including issues of learning outcomes, infrastructure gaps, teacher shortages, and regional disparities. NEP 2020 aims to transform India's education system by 2040, introducing multidisciplinary approaches, mother-tongue instruction up to Grade 5, and revamped higher education structures.", "exam_angle": "NEP 2020 is a high-priority topic for UPSC — its key provisions, implementation challenges, and connection to SDG 4 (Quality Education) are frequently asked in GS Paper 2 (Social Justice/Governance).", "gs_paper": "GS Paper 2 (Governance)", "key_facts": ["NEP 2020 released: July 29, 2020 (replacing NPE 1986)", "Key targets: 5+3+3+4 curricular structure; GER in higher education to 50% by 2035", "Mother-tongue instruction: Up to Grade 5 (preferably Grade 8)", "ANRF: Anusandhan National Research Foundation set up under NEP to fund research"], "source": "Frontline Magazine", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Hyderabad Names Road After Donald Trump; US President Acknowledges the Honour", "category": "ir", "category_name": "International Relations", "summary": "Hyderabad named a road after US President Donald Trump, marking an unprecedented gesture of goodwill from an Indian city towards the American head of state. Trump acknowledged the honour and thanked India for the gesture. The naming coincides with the broader warming of India-US ties, including ongoing trade deal negotiations and a potential state visit by Trump to India in 2027.", "exam_angle": "India-US bilateral relationship depth (people-to-people ties, Indian diaspora in the US, and diplomatic symbolism) is relevant for GS Paper 2 (IR); also a 'persons in news' item.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["City: Hyderabad named a road after Donald Trump", "Trump acknowledged the honour publicly", "Context: Part of broader India-US diplomatic warming", "Indian-American diaspora: ~4.4 million in the US — politically influential"], "source": "India Today", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "IIT Bombay and SUNY Announce Academic Collaboration in Engineering Education and Research", "category": "scitech", "category_name": "Science & Technology", "summary": "IIT Bombay and the State University of New York (SUNY) announced a formal collaboration in engineering education and research on June 27, 2026. The partnership will involve joint research programmes, faculty exchanges, and student mobility. This collaboration aligns with India's push under NEP 2020 to internationalise higher education and foster global research partnerships.", "exam_angle": "Internationalisation of Indian higher education (NEP 2020 provisions), IIT-foreign university partnerships, and the role of academic diplomacy in India-US relations are relevant for GS Paper 2 (Education/Governance).", "gs_paper": "GS Paper 2 (Governance)", "key_facts": ["Partners: IIT Bombay (India) and SUNY — State University of New York (USA)", "Areas: Engineering education, joint research, faculty/student exchange", "Policy link: NEP 2020 allows top foreign universities to set up campuses in India", "SUNY: One of the largest public university systems in the USA"], "source": "Business Standard", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "India Startup Funding Tops $1 Billion in a Week; CRED Mega-Round Powers Rebound", "category": "economy", "category_name": "Economy & Banking", "summary": "India's startup ecosystem recorded over $1 billion in funding in a single week, driven primarily by a mega funding round for fintech unicorn CRED. This marks a sharp weekly rebound in venture capital activity and signals renewed investor confidence in Indian startups. India remains one of the world's largest startup ecosystems, with over 100 unicorns.", "exam_angle": "India's startup ecosystem, fintech growth, and the role of venture capital are relevant for GS Paper 3 (Economy), connecting to Startup India initiative and the digital economy.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Weekly funding: Over $1 billion in Indian startups", "Key driver: CRED (fintech unicorn) mega funding round", "India unicorn count: 100+ unicorns", "Relevant scheme: Startup India (launched January 16, 2016)"], "source": "CNBC TV18", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Jharkhand High Court Acquits Man in Witch-Hunting Murder Case Citing Unreliable Evidence", "category": "polity", "category_name": "Polity & Governance", "summary": "The Jharkhand High Court acquitted a 30-year-old man convicted in a witch-hunting related murder case, citing unreliable eyewitness testimony. Witch-hunting remains a serious social problem in Jharkhand, Odisha, Chhattisgarh, and Assam, predominantly affecting women from tribal communities. Jharkhand enacted the Prevention of Witch (Daain) Practices Act in 1999 to address this issue.", "exam_angle": "Witch-hunting as a form of social violence against women and tribal communities, state legislation on the issue, and tribal rights are relevant for GS Paper 1 (Society) and GS Paper 2 (Social Justice).", "gs_paper": "GS Paper 1 (Society)", "key_facts": ["Court: Jharkhand High Court", "Issue: Witch-hunting murder case — acquittal on evidentiary grounds", "Jharkhand Act: Prevention of Witch (Daain) Practices Act, 1999", "Vulnerable groups: Tribal women disproportionately targeted in witch-hunting incidents"], "source": "The New Indian Express", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Government Releases Names of Six Soldiers Killed During Operation Sindoor", "category": "defence", "category_name": "Defence & Security", "summary": "The Indian government publicly released the names of six military personnel killed in action during Operation Sindoor for the first time. This marks an official acknowledgement of personnel casualties from the operation. The disclosure was widely reported by NDTV, The Hindu, and Scroll.in on June 26, 2026. Operation Sindoor had previously been in the news for India's military actions against Pakistan-based terror infrastructure.", "exam_angle": "Operation Sindoor is significant for GS Paper 3 (Internal Security & Defence); questions may arise on India's military operations, casualty disclosure norms, and civil-military relations.", "gs_paper": "GS Paper 3 (Defence & Internal Security)", "key_facts": ["Six military personnel killed in action during Operation Sindoor", "Names released publicly for the first time on June 26, 2026", "Reported by NDTV, The Hindu, Scroll.in"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Mahesh Dixit Appointed as New Chief of Intelligence Bureau", "category": "persons", "category_name": "Persons & Awards in News", "summary": "IPS officer Mahesh Dixit has been appointed as the new chief of the Intelligence Bureau (IB), India's domestic intelligence agency. Dixit is notable for being a doctor-turned-IPS officer, making him India's first medical doctor to head the Intelligence Bureau. He is credited with steady crisis management and consensus-building, particularly in Jammu & Kashmir and Leh. His appointment comes amid a broader cabinet/security establishment reshuffle.", "exam_angle": "IB chief appointments are frequently asked in 'Persons in News' sections; the IB operates under the Ministry of Home Affairs and is India's primary internal intelligence agency — relevant to GS Paper 2 (Governance) and GS Paper 3 (Internal Security).", "gs_paper": "GS Paper 3 (Internal Security)", "key_facts": ["Mahesh Dixit appointed as Intelligence Bureau (IB) chief", "First medical doctor (MBBS) to head IB in India", "IPS officer with experience in J&K and Leh postings", "IB functions under Ministry of Home Affairs"], "source": "Hindustan Times", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Japan PM Sanae Takaichi to Visit India (July 1–3) for Annual India-Japan Summit", "category": "ir", "category_name": "International Relations", "summary": "Japanese Prime Minister Sanae Takaichi is scheduled to visit India from July 1 to 3, 2026, for the Annual India-Japan Summit. The visit is part of the institutionalised annual bilateral summit mechanism between the two countries. India and Japan share a Special Strategic and Global Partnership. Key agenda items are expected to include defence cooperation, infrastructure investment (including bullet train project), and technology collaboration.", "exam_angle": "India-Japan Annual Summit is a recurring exam topic under GS Paper 2 (IR); Japan is India's key partner in defence, infrastructure (bullet train), and QUAD — aspirants must track PM-level visits and outcomes.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Japan PM Sanae Takaichi to visit India: July 1–3, 2026", "Annual India-Japan Summit mechanism", "India-Japan relationship: Special Strategic and Global Partnership", "Japan is QUAD partner along with India, USA, Australia"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "India Launches 'Operation Amistad' — Dispatches Relief and Medical Aid to Earthquake-Hit Venezuela", "category": "ir", "category_name": "International Relations", "summary": "India launched 'Operation Amistad' (meaning 'friendship' in Spanish) to dispatch humanitarian relief and medical aid to Venezuela, which was struck by devastating earthquakes with a death toll exceeding 589 and over 2,900 injured. The operation reflects India's growing role as a first responder in international humanitarian crises. India has previously conducted similar operations such as Operation Dost (Turkey/Syria earthquake, 2023) and Operation Kaveri (Sudan, 2023).", "exam_angle": "India's humanitarian diplomacy and disaster relief operations are important for GS Paper 2 (IR); 'Operation Amistad' connects to India's 'Neighbourhood First' and 'Global South' diplomacy narratives.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Operation Amistad: India's relief operation to Venezuela", "Venezuela earthquake toll: 589+ dead, 2,900+ injured (as of June 26, 2026)", "'Amistad' means friendship in Spanish", "Similar past ops: Operation Dost (Turkey, 2023), Operation Kaveri (Sudan, 2023)"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Bangladesh PM and Chinese Water Minister Discuss Teesta River Plan Implementation", "category": "ir", "category_name": "International Relations", "summary": "Bangladesh Prime Minister Tarique Rahman and China's Water Minister held discussions on implementing the Teesta River management plan. China has proposed a $1 billion Teesta River comprehensive management project, which has been a contentious issue in India-Bangladesh-China triangular relations. China also reaffirmed support for Bangladesh's new government and expressed expectations for high-quality Belt and Road Initiative (BRI) cooperation. Bangladesh also urged China to reduce the bilateral trade deficit.", "exam_angle": "The Teesta River dispute is a long-standing India-Bangladesh bilateral issue; China's involvement introduces a strategic triangular dimension critical for GS Paper 2 (IR) — Brahmaputra/Teesta water-sharing and China's BRI expansion in South Asia.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Bangladesh PM Tarique Rahman discussed Teesta Plan with Chinese Water Minister", "China has proposed ~$1 billion Teesta comprehensive management project", "Teesta river originates in Sikkim, flows through West Bengal into Bangladesh", "China's BRI cooperation reaffirmed with Bangladesh's interim government"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "UN Suspends Ship Evacuation in Strait of Hormuz After Attack on Vessel off Oman", "category": "ir", "category_name": "International Relations", "summary": "The United Nations suspended its ship evacuation effort in the Strait of Hormuz after a cargo vessel was attacked off the coast of Oman. Iran was reported to have attacked the cargo ship, testing a recently negotiated US-Iran deal aimed at reopening the Strait. The International Maritime Organization (IMO) had announced an evacuation plan for the area. The Strait of Hormuz is a critical global oil and trade chokepoint through which approximately 20% of global oil supply transits.", "exam_angle": "The Strait of Hormuz is a key strategic chokepoint for global energy security — directly relevant to GS Paper 3 (Energy Security) and GS Paper 2 (IR); India imports significant oil through this route.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["UN suspended ship evacuation in Strait of Hormuz after attack off Oman", "IMO (International Maritime Organization) had announced an evacuation plan", "Strait of Hormuz: ~20% of global oil supply transits through it", "Iran accused of attacking the cargo vessel"], "source": "Telegraph India", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Iran Proposes $40 Billion Plan to Charge Ships Transiting Strait of Hormuz", "category": "ir", "category_name": "International Relations", "summary": "Iran proposed a $40 billion plan to levy charges on ships passing through the Strait of Hormuz, one of the world's most critical maritime chokepoints. The proposal comes amid ongoing tensions in the region following drone strikes and cargo ship attacks. The Strait connects the Persian Gulf to the Arabian Sea and is vital for global oil supply chains. Such a move would have significant implications for global trade and energy markets.", "exam_angle": "Relevant for GS Paper 3 (Economy — Energy Security) and GS Paper 2 (IR); India's energy import vulnerability through the Persian Gulf makes Hormuz-related developments directly exam-relevant.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Iran proposed $40 billion plan to charge vessels transiting Strait of Hormuz", "Strait of Hormuz: key chokepoint between Persian Gulf and Arabian Sea", "Approximately 20-21 million barrels of oil transit daily through the Strait"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "NIA Files Chargesheet Against 11 Bangladeshi Terrorists", "category": "polity", "category_name": "Polity & Governance", "summary": "India's National Investigation Agency (NIA) filed a chargesheet against 11 Bangladeshi nationals accused of terrorism-related offences. The chargesheet is part of NIA's ongoing efforts to counter cross-border terrorism originating from Bangladesh. The NIA operates under the Ministry of Home Affairs and was established under the National Investigation Agency Act, 2008. The development comes against the backdrop of changing political dynamics in Bangladesh following the fall of the Sheikh Hasina government.", "exam_angle": "NIA's mandate, jurisdiction, and counter-terrorism chargesheets are standard GS Paper 3 (Internal Security) topics; Bangladesh-linked terrorism and India's border security challenges are also important.", "gs_paper": "GS Paper 3 (Internal Security)", "key_facts": ["NIA (National Investigation Agency) filed chargesheet against 11 Bangladeshi terrorists", "NIA established under National Investigation Agency Act, 2008", "NIA functions under Ministry of Home Affairs", "Chargesheet relates to cross-border terrorism from Bangladesh"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Europe's 2026 Heatwave 'Virtually Impossible' Without Climate Change, Scientists Confirm", "category": "environment", "category_name": "Environment & Ecology", "summary": "Scientists from World Weather Attribution (WWA) concluded that the 2026 European heatwave was 'virtually impossible' without human-induced climate change, calling it the worst ever recorded. Paris restricted alcohol consumption and sales as temperatures soared. The extreme heat event demonstrates accelerating climate attribution — the science linking specific weather events to climate change. Such rapid-onset extreme weather has implications for public health, agriculture, and energy systems globally.", "exam_angle": "Climate attribution science and extreme weather events are central to GS Paper 3 (Environment); World Weather Attribution (WWA) is a key body to know for reports on climate-weather linkages.", "gs_paper": "GS Paper 3 (Environment)", "key_facts": ["2026 European heatwave declared 'virtually impossible' without climate change", "Assessed by World Weather Attribution (WWA) scientists", "Declared the worst heatwave ever recorded in Europe", "Paris restricted alcohol sales and consumption during heatwave"], "source": "Reuters", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "India-US Trade Deal Talks: Trump Administration Warns Old Tariffs May Return", "category": "economy", "category_name": "Economy & Banking", "summary": "Amid ongoing India-US trade deal negotiations, the Trump administration issued a fresh warning that old (pre-deal) tariffs may return if negotiations fail to conclude favourably. Two-day trade talks were underway with India seeking a competitive edge in US markets, while the US focused on market access and reducing trade deficits. India is seeking preferential tariff treatment especially for its IT, pharmaceuticals, and textile exports. The talks are set against the backdrop of Trump's broader global tariff pressure campaign.", "exam_angle": "India-US trade relations, tariff regimes, and bilateral trade deal negotiations are important for GS Paper 2 (IR) and GS Paper 3 (Economy); WTO, MFN clauses, and trade defence measures are related concepts.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["India-US trade deal talks ongoing as of June 26, 2026", "Trump administration warned old tariffs may return if talks fail", "India seeks competitive market access in sectors like IT, pharma, textiles", "US seeks reduced trade deficit and greater market access in India"], "source": "The Times of India", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Goldman Sachs Raises India GDP Growth Forecast to 6.8% for 2026", "category": "economy", "category_name": "Economy & Banking", "summary": "Goldman Sachs raised its GDP growth forecast for India to 6.8% for 2026, partially attributing the upward revision to the US-Iran deal that has helped ease global oil price pressures. Lower crude oil prices benefit India significantly given its heavy dependence on oil imports (~85% of requirements). The revision reflects improving macro conditions and strong domestic demand. India remains one of the fastest-growing major economies globally.", "exam_angle": "GDP forecasts by global institutions (Goldman Sachs, IMF, World Bank) are standard 'reports' questions in UPSC Prelims and GS Paper 3 (Economy); India's crude oil import dependency is a key economic vulnerability.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Goldman Sachs raised India GDP forecast to 6.8% for 2026", "Revision partly attributed to US-Iran deal easing oil prices", "India imports ~85% of its crude oil requirements", "India remains among the fastest-growing major economies"], "source": "Business Standard", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Amazon CEO Andy Jassy Announces $48 Billion Investment Plan for India", "category": "economy", "category_name": "Economy & Banking", "summary": "Amazon CEO Andy Jassy announced a $48 billion investment plan for India, with a significant focus on Amazon Web Services (AWS) cloud infrastructure and Artificial Intelligence. The investment is one of the largest ever announced by a foreign tech company for India. It follows earlier commitments by major tech firms like Google and Microsoft in India's digital infrastructure. The announcement signals India's growing importance as a global technology and cloud services hub.", "exam_angle": "FDI inflows, particularly in technology and cloud infrastructure, are relevant for GS Paper 3 (Economy) and GS Paper 2 (IR — India-US tech relations); Digital India and National Cloud Policy are related government initiatives.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Amazon CEO Andy Jassy announced $48 billion investment in India", "Focus areas: AWS cloud infrastructure and Artificial Intelligence", "One of the largest single-company FDI commitments to India by a tech firm", "Reinforces India's positioning as a global digital and cloud hub"], "source": "News18", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Nasscom: India's AI Services Revenue Reaches $10–12 Billion", "category": "reports", "category_name": "Reports & Indices", "summary": "Industry body Nasscom reported that India's IT companies are generating $10–12 billion in revenue from Artificial Intelligence services, signalling that AI adoption has moved beyond pilots to mainstream deployment. The data reflects India's growing strength in AI-enabled IT services globally. Nasscom is the apex body of the Indian IT industry. This development has implications for India's digital economy targets and employment in the tech sector.", "exam_angle": "Nasscom reports and India's AI/IT industry statistics are important for GS Paper 3 (Economy & Sci-Tech); AI governance, India's National AI Strategy (INDIAai Mission), and digital economy are connected themes.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["India's IT industry AI services revenue: $10–12 billion (Nasscom, 2026)", "AI adoption has moved from pilots to mainstream deployment", "Nasscom: National Association of Software and Service Companies (apex IT industry body)"], "source": "Business Standard", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "RBI's AI Risk Framework to Strengthen Governance and Oversight of AI Models in Banking", "category": "economy", "category_name": "Economy & Banking", "summary": "The Reserve Bank of India (RBI) announced an AI risk framework aimed at strengthening governance and oversight of AI models used by banks and financial institutions. The framework will address risks such as model bias, opacity ('black box' problem), data privacy, and systemic risk from AI in financial decision-making. This is part of RBI's broader regulatory technology (RegTech) initiatives. India's banking sector is increasingly deploying AI for credit underwriting, fraud detection, and customer service.", "exam_angle": "RBI's regulatory frameworks are central to GS Paper 3 (Economy); AI regulation in banking is an emerging topic connecting GS Paper 3 (Sci-Tech) and financial sector governance.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["RBI announced an AI Risk Framework for banks and financial institutions", "Addresses risks: model bias, opacity, data privacy, systemic risk", "Part of RBI's RegTech (Regulatory Technology) initiatives", "RBI regulates commercial banks under RBI Act, 1934 and Banking Regulation Act, 1949"], "source": "Business Standard", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "India Tops Medal Tally at ISSF Junior World Championship in Germany", "category": "reports", "category_name": "Reports & Indices", "summary": "India's shooters topped the medal tally at the ISSF (International Shooting Sport Federation) Junior World Championship held in Germany. India's shooting contingent has been consistently performing at the international level, building on successes at the 2024 Paris Olympics where Indian shooters won multiple medals. The ISSF Junior World Championship is a key feeder competition for the senior international circuit and Olympics qualification.", "exam_angle": "India's performance in international shooting championships is relevant for Prelims 'Sports' current affairs; ISSF and Olympic shooting qualification processes are associated concepts.", "gs_paper": "GS Paper 1 (Culture)", "key_facts": ["India topped medal tally at ISSF Junior World Championship 2026", "Championship held in Germany", "ISSF: International Shooting Sport Federation (governing body for Olympic shooting)"], "source": "The Times of India", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Nihang Sikhs Breach Barricades at Uttarakhand Border, Standoff Resolved After Talks", "category": "polity", "category_name": "Polity & Governance", "summary": "A tense standoff occurred at Uttarakhand's border when Nihang Sikhs breached police barricades while heading towards Hemkund Sahib, a prominent Sikh shrine located in Chamoli district at an altitude of 4,329 metres in the Himalayas. The situation normalised after talks between Nihang groups and police, and those involved left without further incident. Hemkund Sahib is associated with Guru Gobind Singh and is mentioned in the Dasam Granth. The episode raised questions about management of pilgrimage routes and law enforcement.", "exam_angle": "Hemkund Sahib and Nihang Sikhs connect to GS Paper 1 (Culture/Art & Heritage) and GS Paper 2 (Polity — law & order, federalism); places of religious significance in Uttarakhand are frequently asked.", "gs_paper": "GS Paper 1 (Culture)", "key_facts": ["Nihang Sikhs breached barricades at Uttarakhand border heading to Hemkund Sahib", "Hemkund Sahib: Sikh shrine in Chamoli district, Uttarakhand at ~4,329 m altitude", "Standoff resolved after talks; Nihangs left peacefully", "Hemkund Sahib associated with Guru Gobind Singh (mentioned in Dasam Granth)"], "source": "The Hindu", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Micromax-Phison JV 'MiPhi' Plans Rs 1,000 Crore Investment in AI Memory Chip Manufacturing", "category": "scitech", "category_name": "Science & Technology", "summary": "MiPhi, a joint venture between India's Micromax and Taiwan's Phison Electronics, announced plans to invest Rs 1,000 crore in India's AI memory chip sector. The investment aims to capitalise on India's growing AI infrastructure boom and aligns with the government's India Semiconductor Mission (ISM) to develop domestic semiconductor manufacturing capabilities. India has been actively attracting semiconductor companies with financial incentives under the Semicon India Programme. The move signals growing confidence in India as a destination for advanced chip manufacturing.", "exam_angle": "India Semiconductor Mission, Semicon India Programme, and domestic chip manufacturing are important for GS Paper 3 (Sci-Tech & Economy); semiconductor geopolitics is an emerging UPSC theme.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["MiPhi JV (Micromax + Phison Electronics) to invest Rs 1,000 crore in AI memory chips", "Aligns with India Semiconductor Mission (ISM) under Ministry of Electronics & IT", "Semicon India Programme provides ~50% fiscal support for chip manufacturing", "Phison Electronics is a Taiwan-based NAND flash controller chip company"], "source": "Moneycontrol", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Indian Air Force Assists Rescue Operations After Flash Floods in Arunachal Pradesh", "category": "defence", "category_name": "Defence & Security", "summary": "The Indian Air Force (IAF) deployed aircraft to assist rescue and relief operations following flash floods in Arunachal Pradesh. Flash floods are a recurring disaster in Arunachal Pradesh due to its mountainous terrain, high rainfall, and glacial lake outburst floods (GLOFs). The IAF regularly plays a critical role in disaster relief operations in the Northeast and other difficult terrains under the framework of civil-military coordination in disaster management. The NDRF and SDRF typically operate alongside military forces in such situations.", "exam_angle": "IAF's role in disaster relief and civil-military cooperation in NDMA framework are relevant for GS Paper 3 (Disaster Management); Arunachal Pradesh's vulnerability to GLOFs and flash floods is relevant for GS Paper 1 (Geography).", "gs_paper": "GS Paper 3 (Disaster Management)", "key_facts": ["IAF deployed for rescue operations after Arunachal Pradesh flash floods", "Flash floods common in Arunachal due to GLOFs (Glacial Lake Outburst Floods) and heavy rainfall", "IAF operates under Ministry of Defence; disaster relief under NDMA framework", "NDRF (National Disaster Response Force) also deploys in such emergencies"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Piyush Goyal Questions Global Credit Rating Agencies Over Undervaluation of India's Growth Story", "category": "economy", "category_name": "Economy & Banking", "summary": "Union Minister Piyush Goyal publicly questioned the credibility and methodology of global credit rating agencies, stating that India's growth story has been chronically undervalued by these agencies. India has long maintained that its sovereign credit rating (Baa3/BBB- by Moody's/S&P/Fitch — lowest investment grade) does not accurately reflect its macroeconomic fundamentals and growth trajectory. India has previously submitted detailed rebuttals to rating agencies through the Ministry of Finance. The statement reflects ongoing tension between India's economic performance and its international credit standing.", "exam_angle": "Sovereign credit ratings, their methodology, and India's rating dispute are important for GS Paper 3 (Economy); Moody's, S&P, Fitch are the 'Big Three' rating agencies — frequently mentioned in economic editorials.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Minister Piyush Goyal criticised global credit rating agencies for undervaluing India", "India's sovereign rating: Baa3 (Moody's), BBB- (S&P/Fitch) — lowest investment grade", "India has formally challenged rating methodologies through Ministry of Finance", "Big Three rating agencies: Moody's, S&P Global, Fitch Ratings"], "source": "Moneycontrol", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "India Pushes for Stable AI Technology Access from USA After Mythos Suspension", "category": "scitech", "category_name": "Science & Technology", "summary": "India has formally pushed for stable and uninterrupted access to AI technology from the United States following the suspension of 'Mythos', an AI system that India was accessing. The move reflects India's strategic interest in not being dependent on a single AI supplier and ensuring technology sovereignty. This connects to India's broader push for AI governance frameworks and its National AI Strategy. India is seeking to be included in the US's trusted AI partner framework amid growing US-China AI competition.", "exam_angle": "AI technology access, technology sovereignty, and India-US tech diplomacy are relevant for GS Paper 2 (IR) and GS Paper 3 (Sci-Tech); India's INDIAai Mission and National AI Strategy are related government initiatives.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["India pushing USA for stable AI technology access after 'Mythos' AI suspension", "Reflects concern over technology dependency and AI sovereignty", "India's National AI Strategy overseen by NITI Aayog's INDIAai Mission", "Relevant to India-US Initiative on Critical and Emerging Technology (iCET)"], "source": "MediaNama", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Venezuela Declares State of Emergency After Strongest Twin Earthquakes Since 1900", "category": "places", "category_name": "Places in News", "summary": "Venezuela was struck by two major earthquakes on June 25, 2026, with the event described as the strongest seismic activity in the country since 1900. Thousands are feared dead and President Nicolás Maduro declared a state of emergency. Rescue operations are underway amid scenes of widespread destruction. The international community, including the UN, has responded to the crisis.", "exam_angle": "Significant for GS Paper 1 (Geography) — questions on seismic zones, tectonic plate boundaries (Caribbean Plate), and disaster management frameworks. Also relevant for IR given Venezuela's geopolitical significance.", "gs_paper": "GS Paper 1 (Geography)", "key_facts": ["Strongest earthquake in Venezuela since 1900", "Venezuela declared state of emergency on June 25, 2026", "Thousands feared dead; UN announced evacuation operations", "Venezuela lies near the Caribbean–South American tectonic plate boundary"], "source": "Reuters / BBC / The Guardian", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "India–US Trade Deal: Piyush Goyal Sets 'Comparative Tariff Advantage' as Red Line", "category": "ir", "category_name": "International Relations", "summary": "Union Commerce Minister Piyush Goyal stated on June 25, 2026 that India will not sign a trade deal with the United States unless it secures a comparative tariff advantage over competing nations. India and the US concluded the latest round of talks without finalising a deal. Goyal described the deal as 'very close' but stressed that India needs tariff rates lower than competitors like China and Vietnam. Bloomberg reported 'no clarity' on timing after the latest talks concluded.", "exam_angle": "Core IR + Economy topic: India's trade negotiation strategy, Most Favoured Nation (MFN) principles, and bilateral trade relations under the Trump administration's tariff regime are frequently tested.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["India's condition: comparative tariff advantage framework must be ensured", "Minister involved: Piyush Goyal (Commerce & Industry)", "Talks described as 'very close' to deal but no finalisation as of June 25, 2026", "Key competition cited: China and Vietnam on US tariff rates"], "source": "The Times of India / The Hindu / NDTV / Bloomberg", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "India Resumes Tourist Visas for Bangladeshi Nationals; Envoy Dinesh Trivedi Elevated to Union Minister Rank", "category": "ir", "category_name": "International Relations", "summary": "India announced the resumption of tourist visas for Bangladeshi nationals on June 25, 2026, signalling an easing of bilateral ties after a period of strain following the political transition in Bangladesh. India's new envoy to Bangladesh, Dinesh Trivedi, assumed office and announced the visa resumption. The Centre elevated Trivedi to Union Minister rank for ceremonial protocol purposes. This development comes amid broader diplomatic recalibration between the two neighbours.", "exam_angle": "India–Bangladesh bilateral relations are a staple GS Paper 2 (IR) topic; connects to neighbourhood-first policy, SAARC dynamics, and role of diplomacy in managing post-Hasina Bangladesh.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["India's envoy to Bangladesh: Dinesh Trivedi", "Trivedi elevated to Union Minister rank for ceremonial protocol", "Tourist visas to Bangladeshi nationals resumed: June 2026", "Signals easing of India–Bangladesh ties after 2024 political transition in Dhaka"], "source": "The Times of India / The Hindu", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "India Withdraws Commercial LPG Supply Restrictions Amid US–Iran Deal Hopes", "category": "economy", "category_name": "Economy & Banking", "summary": "India lifted restrictions on commercial LPG supplies to industries on June 25, 2026, a move linked to improving prospects of a US–Iran nuclear/sanctions deal that could ease global energy supplies. Petroleum Minister Hardeep Puri also discussed 'opportunities to cooperate' with his Iranian counterpart after years of curtailed trade due to US sanctions. India had previously curtailed LPG supply to industries to manage domestic shortfall risks. The move signals a recalibration of India's energy security strategy.", "exam_angle": "Connects GS Paper 3 (Energy Security) with GS Paper 2 (IR): India's dependence on West Asian energy, impact of US sanctions on Iranian oil imports, and India's hedging strategy in the Iran–US standoff.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["India lifted commercial LPG supply restrictions: June 25, 2026", "Petroleum Minister: Hardeep Puri", "Trigger: expected US–Iran deal easing global energy markets", "India had drastically reduced Iranian oil imports post-2019 US sanctions (CAATSA concerns)"], "source": "Hindustan Times / Reuters / The Hindu", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Passport Fee Revised from July 1, 2026: New Passport to Cost Rs 2,500; Tatkaal Rs 5,000", "category": "schemes", "category_name": "Govt Schemes & Policies", "summary": "The Government of India announced a revision of passport fees effective July 1, 2026. A fresh/new passport will cost Rs 2,500 (up from earlier rates), while the Tatkaal (urgent) passport fee has been set at Rs 5,000. The fee structure covers both fresh and re-issued documents. The revision is the first significant update to passport fees in several years.", "exam_angle": "Relevant for GS Paper 2 (Governance/Schemes): Passports Act 1967, passport as a citizen-service delivery reform, and e-governance initiatives under MEA. The passport–citizenship distinction (a concurrent legal debate) also tested.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["New passport fee (from July 1, 2026): Rs 2,500", "Tatkaal passport fee: Rs 5,000", "Applies to both fresh issuance and re-issue", "Passports are governed by the Passports Act, 1967"], "source": "Moneycontrol / India Today", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Ram Temple Donation Row: Supreme Court Asks Petitioner to Mention Plea on June 29", "category": "polity", "category_name": "Polity & Governance", "summary": "The Supreme Court of India on June 25, 2026 directed a petitioner seeking a fair probe into alleged embezzlement of donations at the Ram Temple (Ayodhya) to mention the matter on June 29. An FIR has been lodged regarding alleged misappropriation of donations, and two individuals have been arrested. The petitioner has alleged that the SIT formed to investigate the matter is an 'eyewash.' The case involves the Shri Ram Janmabhoomi Teerth Kshetra Trust.", "exam_angle": "Connects to GS Paper 2 (Polity): Supreme Court's supervisory jurisdiction, PIL mechanisms, and accountability of religious trusts. Also relevant for questions on Ayodhya verdict implementation and institutional governance.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["SC directed petitioner to mention plea on June 29, 2026", "FIR lodged for alleged embezzlement of Ram Temple donations", "Two persons arrested in the donations theft case", "Trust involved: Shri Ram Janmabhoomi Teerth Kshetra Trust"], "source": "The Hindu", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "CBI Conducts Searches at 80+ Locations Across 16 States Under 'Operation Chakra-VI' Against Digital Arrest Scams", "category": "polity", "category_name": "Polity & Governance", "summary": "The Central Bureau of Investigation (CBI) launched 'Operation Chakra-VI' on June 25, 2026, conducting searches at over 80 locations across 16 states to crack down on pan-India 'digital arrest' scam networks. Digital arrest scams involve fraudsters posing as law enforcement officials and coercing victims into transferring money under the guise of a fake arrest. The operation targeted key nodes of the cybercrime syndicate. This is the sixth iteration of Operation Chakra, CBI's ongoing series targeting organised cybercrime.", "exam_angle": "GS Paper 3 (Internal Security/Cybersecurity): Digital arrest scams are a growing cybercrime category; CBI's Operation Chakra series, IT Act provisions, and India's cybercrime institutional framework are testable topics.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Operation name: Operation Chakra-VI", "Agency: CBI", "Searches: 80+ locations across 16 states (June 25, 2026)", "Target: 'Digital arrest' scam syndicates — fraudsters impersonating police/ED/CBI to extort victims"], "source": "The Hindu / The New Indian Express / The Times of India", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Canada Officially Attributes 1985 Air India Bombing to Khalistanis for the First Time", "category": "ir", "category_name": "International Relations", "summary": "Canada officially stated for the first time that Khalistani extremists were responsible for the 1985 Air India Flight 182 bombing, which killed 329 people — the deadliest terrorist attack in Canadian history and the deadliest aviation attack before 9/11. This marks a significant diplomatic and legal development in India–Canada relations, as India had long maintained that Canada-based Khalistani groups were behind the attack. The declaration comes amid ongoing India–Canada tensions over the Nijjar case.", "exam_angle": "High-value IR topic: India–Canada relations, Khalistani extremism, Five Eyes intelligence, and state accountability for diaspora terrorism. Connects to GS Paper 2 (IR) and GS Paper 3 (Internal Security).", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Air India Flight 182 bombed: June 23, 1985; 329 killed", "Canada's first official attribution of the bombing to Khalistani groups: June 2026", "The attack remains Canada's deadliest terrorist incident", "Context: India–Canada diplomatic tensions over Hardeep Singh Nijjar case (2023–present)"], "source": "India Today", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "NIA: Pahalgam Terror Attack Plot Was in Motion a Week Before Strike; April 15 Reconnaissance Trip Confirmed", "category": "defence", "category_name": "Defence & Security", "summary": "The National Investigation Agency (NIA) revealed on June 25, 2026 that the Pahalgam terror attack plot was in motion at least a week before the strike, with a reconnaissance trip conducted on April 15, 2026. The NIA's findings detail pre-attack planning and surveillance by the perpetrators. The Pahalgam attack, which targeted tourists in the Baisaran valley of Jammu & Kashmir, triggered a major security and diplomatic crisis between India and Pakistan.", "exam_angle": "GS Paper 3 (Internal Security): NIA's investigative role, cross-border terrorism, India–Pakistan relations post-Pahalgam, and counter-terrorism institutional framework are highly testable.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["NIA confirmed: Pahalgam attack plot active at least one week before the strike", "Reconnaissance trip: April 15, 2026 (approximately one week before the attack)", "Attack location: Baisaran valley, Pahalgam, Jammu & Kashmir", "Investigating agency: National Investigation Agency (NIA)"], "source": "The Indian Express", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Strait of Hormuz Crisis: IMO Announces Evacuation Plan for Stranded Seafarers", "category": "ir", "category_name": "International Relations", "summary": "The International Maritime Organization (IMO) announced an evacuation plan on June 25, 2026 for seafarers stranded in the Strait of Hormuz amid the Iran–US military confrontation. The Strait of Hormuz is the world's most critical oil chokepoint, through which approximately 20% of global oil trade passes. Iran had threatened to close the strait, while the US asserted it had ended Iran's ability to do so. The crisis has significant implications for global energy security and India's oil imports.", "exam_angle": "GS Paper 3 (Energy Security) + GS Paper 2 (IR): Strait of Hormuz is a perennially tested geographic chokepoint; IMO's role, freedom of navigation, and India's energy import dependence on the Persian Gulf are key exam angles.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Strait of Hormuz: separates Iran from Oman/UAE; ~20% of global oil trade passes through it", "IMO announced evacuation plan for stranded seafarers: June 25, 2026", "Iran threatened closure of the strait during US–Iran military confrontation", "IMO: International Maritime Organization, UN specialised agency for shipping"], "source": "The Hindu / UN News", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Amazon CEO Andy Jassy Meets PM Modi; Amazon to Invest $48 Billion in India by 2030", "category": "economy", "category_name": "Economy & Banking", "summary": "Amazon CEO Andy Jassy met Prime Minister Narendra Modi on June 25, 2026 and announced that Amazon will invest $48 billion in India by 2030, covering cloud infrastructure, logistics, digital payments, and other verticals. This is one of the largest foreign direct investment commitments made to India by a technology company. The announcement aligns with India's push to attract global tech investments and strengthen its digital economy.", "exam_angle": "GS Paper 3 (Economy): Foreign Direct Investment (FDI) policy, India's digital economy targets, cloud computing infrastructure, and Make in India/Digital India initiatives are testable connections.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Amazon investment commitment: $48 billion in India by 2030", "Amazon CEO: Andy Jassy", "Meeting: with PM Narendra Modi, June 25, 2026", "Covers cloud infrastructure, logistics, and digital ecosystem expansion"], "source": "News18 / NDTV", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "RBI Directs Banks to Install 'Kill Switches' and Human Oversight Mechanisms for AI Models", "category": "economy", "category_name": "Economy & Banking", "summary": "The Reserve Bank of India (RBI) has directed banks to incorporate 'kill switches' — emergency shutdown mechanisms — and mandatory human oversight for AI models deployed in banking operations. The directive is part of RBI's evolving regulatory framework for responsible AI use in the financial sector. This follows global concerns about AI-driven financial decisions and systemic risks. The move aligns with international standards on AI governance in critical financial infrastructure.", "exam_angle": "GS Paper 3 (Economy/Sci-Tech): RBI's regulatory role, AI governance in banking, financial stability, and the intersection of technology regulation with monetary policy are increasingly tested.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["RBI directive: banks must add 'kill switches' and human oversight for AI models", "Purpose: risk mitigation and accountability in AI-driven banking decisions", "Aligns with global AI governance frameworks (e.g., EU AI Act principles)", "Regulatory body: Reserve Bank of India (RBI)"], "source": "MediaNama", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "OpenAI Unveils Custom AI Chip 'Jalapeno' to Reduce Dependence on Nvidia", "category": "scitech", "category_name": "Science & Technology", "summary": "OpenAI unveiled its proprietary AI chip named 'Jalapeno' on June 25, 2026, marking a significant step in the company's strategy to develop in-house semiconductor infrastructure and reduce dependence on Nvidia's GPUs. The chip is designed to accelerate AI model training and inference at scale. This development is part of a broader trend of major AI companies — including Google (TPUs) and Amazon (Trainium) — developing custom chips to gain cost and performance advantages.", "exam_angle": "GS Paper 3 (Sci-Tech): AI chip development, semiconductor geopolitics, US–China chip war, and India's semiconductor mission are testable; OpenAI's vertical integration strategy is a current affairs landmark.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["OpenAI's custom AI chip name: Jalapeno", "Unveiled: June 25, 2026", "Purpose: reduce dependence on Nvidia GPUs for AI training/inference", "Trend: Google (TPU), Amazon (Trainium/Inferentia), Meta (MTIA) — all developing custom AI chips"], "source": "The Hindu", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Anthropic Accuses Alibaba of Illicitly Accessing Claude AI Models via Fake Accounts", "category": "scitech", "category_name": "Science & Technology", "summary": "US AI company Anthropic accused Chinese tech giant Alibaba of illicitly accessing its Claude AI models through fake accounts to extract and replicate AI capabilities — a form of model theft. Anthropic has taken legal action and also announced a shutdown of Alibaba's access. The case highlights the intensifying technological rivalry between US and Chinese AI companies and raises questions about AI intellectual property protection.", "exam_angle": "GS Paper 3 (Sci-Tech) + GS Paper 2 (IR): US–China tech war, AI intellectual property, export controls on AI models, and cybersecurity dimensions of AI development are relevant for UPSC.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Accuser: Anthropic (US AI company, maker of Claude AI)", "Accused: Alibaba (Chinese tech conglomerate)", "Method alleged: fake accounts used to extract Claude AI capabilities", "Broader context: US–China AI technology rivalry and semiconductor/AI export controls"], "source": "Bloomberg / NDTV Profit / Moneycontrol", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "India's Future Security to Be Shaped by AI and Quantum Technology: Minister Jitendra Singh", "category": "scitech", "category_name": "Science & Technology", "summary": "Union Minister of State for Science and Technology Jitendra Singh stated on June 25, 2026 that India's future security architecture will be fundamentally shaped by artificial intelligence and quantum technologies. He was speaking in the context of India's national technology missions. India has ongoing missions — the National Quantum Mission (NQM) and IndiaAI Mission — as part of its strategic technology investments to enhance both defence and civilian capabilities.", "exam_angle": "GS Paper 3 (Sci-Tech/Defence): National Quantum Mission, IndiaAI Mission, dual-use technology in defence, and India's technology sovereignty agenda are frequently tested topics.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Statement by: MoS Science & Technology, Dr. Jitendra Singh", "National Quantum Mission (NQM): approved 2023, outlay Rs 6,003 crore over 8 years", "IndiaAI Mission: launched 2024, Rs 10,372 crore over 5 years", "AI and quantum tech identified as pillars of India's future security infrastructure"], "source": "The New Indian Express", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Government Pushes Private Banks to Expand Enrolments Under PMSBY Accident Insurance Scheme", "category": "schemes", "category_name": "Govt Schemes & Policies", "summary": "The Government of India has directed private sector banks to significantly expand enrolments under the Pradhan Mantri Suraksha Bima Yojana (PMSBY), an accident insurance scheme providing Rs 2 lakh coverage for Rs 20 annual premium. Private banks have lagged behind public sector banks in enrolment figures. The push is part of the government's financial inclusion and social security agenda. PMSBY was launched in 2015 along with PMJJBY (life insurance) and APY (pension scheme) as part of the Jan Suraksha social security package.", "exam_angle": "GS Paper 2 (Schemes/Governance): Jan Suraksha schemes — PMSBY, PMJJBY, APY — are standard exam topics for their coverage, premium, launch year, and implementing ministry.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Scheme: Pradhan Mantri Suraksha Bima Yojana (PMSBY)", "Coverage: Rs 2 lakh for accidental death/permanent disability; Rs 1 lakh for partial disability", "Annual premium: Rs 20", "Launched: 2015; part of Jan Suraksha package along with PMJJBY and APY"], "source": "Mint", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Tungabhadra Dam Gets New Spillway Gates; Karnataka, Andhra Pradesh and Telangana Reach Water-Sharing Consensus", "category": "places", "category_name": "Places in News", "summary": "The 33 new spillway gates of the Tungabhadra Dam were inaugurated on June 25, 2026 by Chief Ministers of Karnataka, Andhra Pradesh, and Telangana, signalling a resolution of inter-state water-sharing tensions. The old gates had been a source of dispute and safety concerns. The three states also reached a consensus on water-sharing modalities from the Tungabhadra reservoir. The Tungabhadra Dam is a joint project of Karnataka and the erstwhile undivided Andhra Pradesh, located at Hospet (now Vijayanagara district), Karnataka.", "exam_angle": "GS Paper 2 (Polity/IR): Inter-state river water disputes, role of river water tribunals, and cooperative federalism in managing shared water resources are frequently tested. Tungabhadra is a tributary of the Krishna River.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Tungabhadra Dam location: Hospet, Vijayanagara district, Karnataka", "River: Tungabhadra (tributary of Krishna River)", "33 new spillway gates inaugurated: June 25, 2026", "States involved: Karnataka, Andhra Pradesh, Telangana — reached water-sharing consensus"], "source": "The Hindu / Deccan Chronicle", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "SBI Report: India's Economy Remains Strong Despite Fifth-Driest June in 125 Years", "category": "economy", "category_name": "Economy & Banking", "summary": "A report by the State Bank of India (SBI) released on June 25, 2026 noted that India's economy remains resilient despite June 2026 being the fifth-driest month of June in the past 125 years. The report highlighted India's macroeconomic fundamentals holding up amid global uncertainties, including geopolitical tensions and trade disruptions. The drought-like conditions in June raise concerns about kharif crop output and rural demand but have not yet significantly dented broader economic indicators.", "exam_angle": "GS Paper 3 (Economy/Agriculture): Monsoon's impact on Indian agriculture, kharif crop dependence on June-July rains, and India's economic resilience indicators are important exam themes.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["June 2026: fifth-driest June in 125 years of recorded Indian meteorological history", "Source: SBI Research report, June 2026", "India's economy described as 'strong' despite rainfall deficit", "Concern: impact on kharif sowing, rural incomes, and food inflation"], "source": "Moneycontrol", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "India Tech Startup Funding Rises 12% to $7.2 Billion in H1 2026, but Deal Count Shrinks", "category": "economy", "category_name": "Economy & Banking", "summary": "India's technology startup ecosystem raised $7.2 billion in funding in the first half of 2026 (H1 2026), a 12% increase year-on-year, according to a Business Standard report. However, the number of individual deals declined, indicating larger deal sizes with fewer but more mature startups receiving capital. The data reflects a trend towards consolidation in the Indian startup ecosystem after the 2022–23 funding winter.", "exam_angle": "GS Paper 3 (Economy): India's startup ecosystem, FDI and venture capital flows, DPIIT's Startup India programme, and India's position in global startup rankings are testable topics.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["India tech startup funding H1 2026: $7.2 billion (up 12% year-on-year)", "Deal count declined despite higher total funding value", "Indicates consolidation: fewer but larger deals", "India ranks 3rd globally in startup count (after USA and China) per DPIIT data"], "source": "Business Standard", "day": "2026-06-25", "day_label": "25 Jun"}], "categories": [{"id": "polity", "name": "Polity & Governance"}, {"id": "economy", "name": "Economy & Banking"}, {"id": "ir", "name": "International Relations"}, {"id": "environment", "name": "Environment & Ecology"}, {"id": "scitech", "name": "Science & Technology"}, {"id": "schemes", "name": "Govt Schemes & Policies"}, {"id": "defence", "name": "Defence & Security"}, {"id": "reports", "name": "Reports & Indices"}, {"id": "persons", "name": "Persons & Awards in News"}, {"id": "places", "name": "Places in News"}]};